{
  "parameters": "z.object({ targetEntityId: z.union([z.number().int(), z.string()]).describe("The entity ID of the hostile mob to attack from the environment snapshot"), weaponName: z.string().default("stone_sword").describe("The preferred weapon to equip before attacking"), maxDistanceBlocks: z.number().int().min(4).max(64).default(32).describe("The maximum distance to chase the target before giving up") })",
  "executionArgs": {
    "targetEntityId": 16,
    "weaponName": "stone_sword",
    "maxDistanceBlocks": 32
  },
  "code": "const targetEntityId = String(args.targetEntityId);
const weaponName = args.weaponName.toLowerCase();
const pollMs = 100;
const findWeapon = function () {
  return bot.inventory.items().find(function (item) {
    const name = item.name.toLowerCase();
    const display = (item.displayName || '').toLowerCase();
    return name.includes(weaponName) || display.includes(weaponName);
  });
};
const findTarget = function () {
  const entity = bot.entities[targetEntityId];
  if (entity && entity.isValid && (entity.kind === 'Hostile mobs' || entity.type === 'hostile' || entity.name === 'zombie' || entity.name === 'skeleton')) {
    return entity;
  }
  return null;
};
if (!bot.entity || bot.health <= 0) {
  return '<UNSAFE>: Bot is not alive.';
}
const weapon = findWeapon();
if (!weapon) {
  return '<NO ITEM>: Could not find weapon matching "' + args.weaponName + '" in inventory.';
}
const target = findTarget();
if (!target) {
  return '<NO TARGET>: Could not find a valid hostile entity with ID ' + targetEntityId + '.';
}
startBackgroundSkill(bot, 'melee_attack', async function (token) {
  try {
    if (!await waitUntilWorldActive(bot, token, pollMs)) { return; }
    const liveWeapon = findWeapon();
    if (liveWeapon) {
      await bot.equip(liveWeapon, 'hand');
    }
    if (!bot.pvp) {
       return;
    }
    while (canContinueBotAction(bot, token)) {
      const currentTarget = findTarget();
      if (!currentTarget || (currentTarget.health !== undefined && currentTarget.health <= 0)) {
        break;
      }
      const distance = bot.entity.position.distanceTo(currentTarget.position);
      if (distance > args.maxDistanceBlocks) {
        break;
      }
      if (!await waitUntilWorldActive(bot, token, pollMs)) {
        bot.pvp.stop();
        continue;
      }
      if (bot.pvp.target !== currentTarget) {
        bot.pvp.attack(currentTarget);
      }
      await waitForActiveMs(bot, token, 200, 50);
    }
  } finally {
    if (bot.pvp) {
      bot.pvp.stop();
    }
  }
});
return '<STARTED>: Melee attack strategy initiated against target ' + targetEntityId + '.';"
}

{
  "parameters": "z.object({ hostileEntityId: z.union([z.number().int(), z.string().min(1)]).describe("The entity ID of the hostile mob to attack as seen in the snapshot"), weaponName: z.string().optional().describe("Optional name of the preferred weapon to use, like 'stone_sword'. If not provided, will look for 'sword' or use what is in hand."), maxDurationMs: z.number().int().min(1000).max(120000).default(30000).describe("The maximum active game time in milliseconds to engage in the fight before stopping") })",
  "executionArgs": {
    "hostileEntityId": 15,
    "weaponName": "stone_sword",
    "maxDurationMs": 30000
  },
  "code": "const pollMs = 100;
const targetId = String(args.hostileEntityId);
const weaponQuery = args.weaponName ? args.weaponName.toLowerCase().replace(/\s+/g, '_') : 'sword';
const findTarget = function () {
  return Object.values(bot.entities).find(function (e) {
    return e && e.isValid && String(e.id) === targetId;
  });
};
const findWeapon = function () {
  return bot.inventory.items().find(function (item) {
    const name = item.name.toLowerCase();
    const display = (item.displayName || '').toLowerCase();
    return name.includes(weaponQuery) || display.includes(weaponQuery);
  });
};
if (!bot.entity || bot.health <= 0) {
  return '<UNSAFE>: Bot is dead or missing.';
}
const target = findTarget();
if (!target) {
  return '<NO TARGET>: Could not find entity with id ' + targetId + '.';
}
const weapon = findWeapon();
startBackgroundSkill(bot, 'melee_attack', async function (token) {
  try {
    if (!await waitUntilWorldActive(bot, token, pollMs)) {
      return;
    }
    if (weapon) {
      await bot.equip(weapon, 'hand');
    }
    if (!canContinueBotAction(bot, token)) {
      return;
    }
    const currentTarget = findTarget();
    if (!currentTarget) {
      return;
    }
    if (bot.pvp && typeof bot.pvp.attack === 'function') {
      bot.pvp.attack(currentTarget);
    } else {
      bot.pathfinder.setGoal(new goals.GoalFollow(currentTarget, 2), true);
    }
    let elapsedActiveMs = 0;
    while (canContinueBotAction(bot, token) && elapsedActiveMs < args.maxDurationMs) {
      const t = findTarget();
      if (!t || (t.health !== undefined && t.health <= 0)) {
        break;
      }
      if (!bot.pvp || typeof bot.pvp.attack !== 'function') {
        if (bot.entity.position.distanceTo(t.position) < 3.5) {
          bot.lookAt(t.position.offset(0, (t.height || 1.8) * 0.8, 0));
          bot.attack(t);
        }
      }
      if (!await waitForActiveMs(bot, token, pollMs, pollMs)) {
        break;
      }
      elapsedActiveMs += pollMs;
    }
  } finally {
    if (bot.pvp && typeof bot.pvp.stop === 'function') {
      bot.pvp.stop();
    }
    bot.pathfinder.setGoal(null);
    bot.clearControlStates();
  }
});
return '<STARTED>: Melee attack initiated on ' + (target.name || 'entity') + ' ' + targetId + '.';"
}

{
  "parameters": "z.object({ minDistance: z.number().int().min(5).max(64).default(20).describe("Distance in blocks to maintain from hostile threats"), targetEntityId: z.union([z.number().int(), z.string().min(1)]).optional().describe("Optional specific hostile entity to move away from") })",
  "executionArgs": {
    "minDistance": 20,
    "targetEntityId": 17
  },
  "code": "const hostileNames = new Set(['zombie', 'skeleton', 'husk', 'drowned', 'stray', 'spider', 'creeper', 'witch', 'enderman', 'phantom', 'slime', 'baby_zombie']);
const getThreats = function () {
  const list = [];
  if (args.targetEntityId) {
    const e = bot.entities[String(args.targetEntityId)];
    if (e && e.isValid) {
      list.push(e);
    }
  }
  if (list.length === 0) {
    Object.values(bot.entities).forEach(function (e) {
      if (e && e.isValid && e.position && (e.kind === 'Hostile mobs' || e.type === 'hostile' || hostileNames.has(e.name || ''))) {
        if (e.position.distanceTo(bot.entity.position) < args.minDistance + 10) {
          list.push(e);
        }
      }
    });
  }
  return list;
};
if (!bot.entity || bot.health <= 0) {
  return '<UNSAFE>: Bot is not alive.';
}
const threats = getThreats();
if (threats.length === 0) {
  return '<STOPPED>: No hostile threats detected within retreat range.';
}
const isAlreadySafe = threats.every(function (t) {
  return t.position.distanceTo(bot.entity.position) >= args.minDistance;
});
if (isAlreadySafe) {
  return '<STOPPED>: Already at a safe distance from all detected hostiles.';
}
startBackgroundSkill(bot, 'safety_retreat', async function (token) {
  const pollMs = 200;
  try {
    while (canContinueBotAction(bot, token)) {
      const currentThreats = getThreats();
      if (currentThreats.length === 0) {
        break;
      }
      const safeFromAll = currentThreats.every(function (t) {
        return t.position.distanceTo(bot.entity.position) >= args.minDistance;
      });
      if (safeFromAll) {
        break;
      }
      let centroid = new Vec3(0, 0, 0);
      currentThreats.forEach(function (t) {
        centroid = centroid.plus(t.position);
      });
      centroid = centroid.scaled(1 / currentThreats.length);
      let retreatDir = bot.entity.position.minus(centroid);
      if (retreatDir.length() < 0.1) {
        retreatDir = new Vec3(1, 0, 0);
      }
      const targetPos = bot.entity.position.plus(retreatDir.normalize().scaled(args.minDistance));
      if (!await waitUntilWorldActive(bot, token, pollMs)) {
        return;
      }
      const movements = new Movements(bot);
      movements.canDig = false;
      movements.allowSprinting = true;
      bot.pathfinder.setMovements(movements);
      const goal = new goals.GoalNear(targetPos.x, targetPos.y, targetPos.z, 2);
      bot.pathfinder.setGoal(goal);
      if (!await waitForActiveMs(bot, token, 1000, pollMs)) {
        return;
      }
      if (bot.pathfinder.isGoalSatisfied(goal)) {
        break;
      }
    }
  } finally {
    bot.pathfinder.setGoal(null);
    bot.pathfinder.stop();
    bot.clearControlStates();
  }
});
return '<STARTED>: Commencing retreat to at least ' + args.minDistance + ' blocks away from hostiles.';"
}
